// Tested and verified 3x on 2026-04-01 against Alex Hormozi (2000+ ads)
const COUNTRY = 'ALL'; // Change to 'GB', 'US' etc for geo-specific
const MAX_ADS = 50;

const allItems = $input.all();
const existingIds = new Set();
const competitors = [];

for (const item of allItems) {
  const f = item.json.fields || item.json;
  // Airtable existing ads have Ad Archive ID
  if (f['Ad Archive ID']) {
    existingIds.add(String(f['Ad Archive ID']));
    continue;
  }
  // Competitors have Name + Facebook Page ID
  if (f['Name'] && f['Facebook Page ID']) {
    competitors.push({
      name: f['Name'],
      pageId: f['Facebook Page ID'],
      tier: f['Niche Tier'] || 'Direct'
    });
  }
}

if (competitors.length === 0) return [];

// Return first competitor with existing IDs attached
// n8n will loop through each via splitInBatches
return competitors.map(comp => ({
  json: {
    ...comp,
    url: `https://www.facebook.com/ads/library/?active_status=all&ad_type=all&country=${COUNTRY}&is_targeted_country=false&media_type=all&search_type=page&sort_data[direction]=desc&sort_data[mode]=total_impressions&view_all_page_id=${comp.pageId}`,
    maxAds: MAX_ADS,
    existingIds: [...existingIds]
  }
}));

// Tested 3x on 2026-04-01 — all fields verified against Airtable
const ads = $input.all();
const competitor = $('Loop Competitors').first().json;
const existingIds = new Set(competitor.existingIds || []);
const today = new Date().toISOString().split('T')[0];
const newAds = [];
let position = 0;

for (const item of ads) {
  const ad = item.json;
  position++;
  if (ad.error) continue;

  const archiveId = String(ad.ad_archive_id || ad.adArchiveId || '');
  if (!archiveId || existingIds.has(archiveId)) continue;

  // Parse dates
  let startDate = null;
  const startRaw = ad.start_date_formatted || ad.startDateFormatted || ad.start_date;
  if (startRaw) {
    if (typeof startRaw === 'string' && startRaw.includes('-')) startDate = startRaw.split(' ')[0];
    else if (typeof startRaw === 'number') startDate = new Date(startRaw * 1000).toISOString().split('T')[0];
  }

  let endDate = null;
  const endRaw = ad.end_date_formatted || ad.endDateFormatted || ad.end_date;
  if (endRaw) {
    if (typeof endRaw === 'string' && endRaw.includes('-')) endDate = endRaw.split(' ')[0];
    else if (typeof endRaw === 'number') endDate = new Date(endRaw * 1000).toISOString().split('T')[0];
  }

  // Days Active + Longevity Tier
  let daysActive = 0;
  if (startDate) {
    const start = new Date(startDate);
    const end = endDate ? new Date(endDate) : new Date();
    daysActive = Math.floor((end - start) / (1000 * 60 * 60 * 24));
  }
  let tier = 'Killed';
  if (daysActive >= 60) tier = 'Long-Runner';
  else if (daysActive >= 30) tier = 'Performer';
  else if (daysActive >= 14) tier = 'Solid';
  else if (daysActive >= 7) tier = 'Testing';

  const snap = ad.snapshot || {};
  const body = snap.body || {};
  const bodyText = typeof body === 'object' ? (body.text || '') : String(body);
  const displayFormat = (snap.display_format || snap.displayFormat || '').toUpperCase();
  const formatMap = { VIDEO: 'Video', IMAGE: 'Image', CAROUSEL: 'Carousel', DCO: 'DCO' };
  const hookCopy = bodyText.split(/\n/)[0] || '';

  const videos = snap.videos || [];
  const videoUrl = videos.length > 0 ? (videos[0].video_hd_url || videos[0].videoHdUrl || videos[0].video_sd_url || videos[0].videoSdUrl || '') : '';
  const images = snap.images || [];
  const imageUrl = images.length > 0 ? (images[0].original_image_url || images[0].originalImageUrl || '') : '';

  const record = {
    'Ad Archive ID': archiveId,
    'Page Name': snap.page_name || snap.pageName || ad.page_name || '',
    'Page ID': String(ad.page_id || snap.page_id || ''),
    'Ad Library URL': `https://www.facebook.com/ads/library/?id=${archiveId}`,
    'Start Date': startDate,
    'End Date': endDate,
    'Days Active': daysActive,
    'Longevity Tier': tier,
    'Display Format': formatMap[displayFormat] || null,
    'Body Text': bodyText.substring(0, 5000),
    'Title': snap.title || '',
    'CTA Type': snap.cta_type || snap.ctaType || '',
    'CTA Text': snap.cta_text || snap.ctaText || '',
    'Link URL': snap.link_url || snap.linkUrl || '',
    'Video URL': videoUrl,
    'Image URL': imageUrl,
    'Hook Copy': hookCopy.substring(0, 500),
    'Word Count': bodyText.split(/\s+/).filter(w => w).length,
    'Impressions Rank': position,
    'Scrape Date': today,
    'Scrape Batch ID': competitor.name + '-' + today
  };

  // Checkbox: only send true
  if (ad.is_active === true) record['Is Active'] = true;

  // Remove empty fields
  const cleaned = {};
  for (const [k, v] of Object.entries(record)) {
    if (v !== '' && v !== null && v !== undefined && v !== 0) cleaned[k] = v;
  }
  // Always include Days Active even if 0
  cleaned['Days Active'] = daysActive;

  newAds.push(cleaned);
  existingIds.add(archiveId);
}

return newAds.map(ad => ({ json: { fields: ad } }));
